# Let's write a quick C# script to inspect the actual types
cd /tmp/sv-f3f6a0af0d9e4280b539c869e325ca3b/ResearchAgent && cat > /tmp/inspect.csx << 'EOF'
// Quick type inspection
using System.Reflection;
var asm = Assembly.LoadFrom(System.IO.Path.Combine(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
    ".nuget/packages/microsoft.agents.ai/1.3.0/lib/net10.0/Microsoft.Agents.AI.dll"));

var t = asm.GetType("Microsoft.Agents.AI.AgentResponse");
if (t != null)
{
    Console.WriteLine($"AgentResponse: {t}");
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  Prop: {p.Name} : {p.PropertyType}");
}

// Check ChatClientAgentRunOptions
var opts = asm.GetType("Microsoft.Agents.AI.ChatClientAgentRunOptions");
if (opts != null)
{
    Console.WriteLine($"\nChatClientAgentRunOptions:");
    foreach (var p in opts.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  Prop: {p.Name} : {p.PropertyType}");
}

// Check ChatClientAgent.RunAsync return type
var agent = asm.GetType("Microsoft.Agents.AI.ChatClientAgent");
if (agent != null)
{
    Console.WriteLine($"\nChatClientAgent methods:");
    foreach (var m in agent.GetMethods(BindingFlags.Public | BindingFlags.Instance).Where(m => m.Name == "RunAsync"))
        Console.WriteLine($"  {m.Name}({string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))}) => {m.ReturnType}");
}
EOF
