using System.Reflection;

var agentType = typeof(Microsoft.Agents.AI.ChatClientAgent);

// Get RunAsync(string, ...) return type more precisely
foreach (var m in agentType.GetMethods(BindingFlags.Public | BindingFlags.Instance).Where(m => m.Name == "RunAsync" && !m.IsGenericMethod))
{
    var pars = m.GetParameters();
    if (pars.Length > 0 && pars[0].ParameterType == typeof(string))
    {
        var ret = m.ReturnType;
        Console.WriteLine($"Return: {ret.FullName}");
        if (ret.IsGenericType)
        {
            var inner = ret.GetGenericArguments()[0];
            Console.WriteLine($"Inner: {inner.FullName}");
            foreach (var p in inner.GetProperties(BindingFlags.Public | BindingFlags.Instance))
                Console.WriteLine($"  {p.Name}: {p.PropertyType}");
            foreach (var p in inner.GetMethods(BindingFlags.Public | BindingFlags.Instance).Where(x => !x.IsSpecialName))
                Console.WriteLine($"  Method: {p.Name}({string.Join(", ", p.GetParameters().Select(x => x.ParameterType.Name))})");
        }
        break;
    }
}

// Also check AgentRunOptions
var asm = agentType.Assembly;
foreach (var t in asm.GetTypes().Where(t => t.Name == "AgentRunOptions"))
{
    Console.WriteLine($"\n{t.FullName}:");
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.FlattenHierarchy))
        Console.WriteLine($"  {p.Name}: {p.PropertyType}");
}
