using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capabilities to the research agent.
/// Uses DuckDuckGo's HTML endpoint to fetch real search results.
/// </summary>
public sealed partial class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Searches the web for information on a given query. Returns a list of result titles, URLs, and snippets.")]
    public async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";

        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

        using var response = await _httpClient.SendAsync(request, cancellationToken);
        response.EnsureSuccessStatusCode();

        var html = await response.Content.ReadAsStringAsync(cancellationToken);
        return ParseResults(html);
    }

    [Description("Fetches the text content of a web page at the given URL. Use this to read full articles found via search.")]
    public async Task<string> FetchPageAsync(
        [Description("The URL of the web page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

        using var response = await _httpClient.SendAsync(request, cancellationToken);
        response.EnsureSuccessStatusCode();

        var html = await response.Content.ReadAsStringAsync(cancellationToken);
        var text = StripHtml(html);

        // Truncate to avoid overwhelming the context window
        const int maxLength = 4000;
        return text.Length > maxLength
            ? string.Concat(text.AsSpan(0, maxLength), "\n\n[Content truncated...]")
            : text;
    }

    private static List<SearchResult> ParseResults(string html)
    {
        var results = new List<SearchResult>();

        foreach (var match in ResultPattern().Matches(html).Cast<Match>())
        {
            var rawUrl = WebUtility.HtmlDecode(match.Groups["url"].Value);
            var title = StripHtml(WebUtility.HtmlDecode(match.Groups["title"].Value)).Trim();

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            var actualUrl = ExtractActualUrl(rawUrl);
            if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(actualUrl))
                continue;

            results.Add(new SearchResult(title, actualUrl));

            if (results.Count >= 5)
                break;
        }

        // Also extract snippets
        var snippets = SnippetPattern().Matches(html).Cast<Match>().ToList();
        for (var i = 0; i < results.Count && i < snippets.Count; i++)
        {
            results[i] = results[i] with
            {
                Snippet = StripHtml(WebUtility.HtmlDecode(snippets[i].Groups["snippet"].Value)).Trim()
            };
        }

        return results;
    }

    private static string ExtractActualUrl(string ddgUrl)
    {
        // DuckDuckGo redirect format: //duckduckgo.com/l/?uddg=<encoded_url>&...
        if (ddgUrl.Contains("uddg="))
        {
            var match = UddgPattern().Match(ddgUrl);
            if (match.Success)
                return Uri.UnescapeDataString(match.Groups["target"].Value);
        }

        return ddgUrl;
    }

    private static string StripHtml(string html)
    {
        var text = TagPattern().Replace(html, " ");
        text = WhitespacePattern().Replace(text, " ");
        return text.Trim();
    }

    [GeneratedRegex("""<a[^>]+class="result__a"[^>]+href="(?<url>[^"]+)"[^>]*>(?<title>.+?)</a>""", RegexOptions.Singleline)]
    private static partial Regex ResultPattern();

    [GeneratedRegex("""<a[^>]+class="result__snippet"[^>]*>(?<snippet>.+?)</a>""", RegexOptions.Singleline)]
    private static partial Regex SnippetPattern();

    [GeneratedRegex("""uddg=(?<target>[^&]+)""")]
    private static partial Regex UddgPattern();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex TagPattern();

    [GeneratedRegex(@"\s+")]
    private static partial Regex WhitespacePattern();
}

public record SearchResult(string Title, string Url, string? Snippet = null)
{
    public override string ToString() =>
        $"- {Title}\n  URL: {Url}" + (Snippet is not null ? $"\n  {Snippet}" : "");
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities so the agent can record findings
/// during research and later compile them into a summary.
/// </summary>
public sealed class NoteTool
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note. Use this to record key findings, facts, or quotes discovered during research.")]
    public string TakeNote(
        [Description("A short title or topic label for this note")] string title,
        [Description("The detailed content of the note — facts, data, quotes, or observations")] string content)
    {
        var note = new Note(title, content, DateTimeOffset.UtcNow);
        _notes.Add(note);
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieves all research notes taken so far. Use this before writing a final summary to review what you've learned.")]
    public string ReadNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note #{i + 1}: {n.Title} ---\n{n.Content}\n[Recorded at {n.Timestamp:u}]"));
    }

    [Description("Returns the number of notes taken so far.")]
    public int GetNoteCount() => _notes.Count;

    private sealed record Note(string Title, string Content, DateTimeOffset Timestamp);
}

