using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient with function-invocation support ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation(options => options.MaximumIterationsPerRequest = 10)
    .Build();

// --- Create tools ---
using var httpClient = new HttpClient();
var webSearch = new WebSearchTool(httpClient);
var notes = new NoteTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notes.TakeNote),
    AIFunctionFactory.Create(notes.ReadNotes),
    AIFunctionFactory.Create(notes.GetNoteCount),
};

// --- Build the research agent ---
const string instructions = """
    You are a thorough research assistant. Given a topic, you must:

    1. Search the web for information using multiple varied queries.
    2. Fetch and read the most promising pages to gather detailed facts.
    3. Take notes on every key finding — include specific facts, dates, and figures.
    4. After gathering enough information (at least 3 notes), read all your notes.
    5. Produce a well-structured summary with sections, citing your sources.

    Always prefer concrete data over vague statements. If initial searches are
    too broad, refine your queries. Do not fabricate information — only report
    what you find through the search and fetch tools.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes",
    tools: tools);

// --- Get the research topic ---
Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║         AI Research Agent                ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.ResetColor();
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "";
    if (string.IsNullOrEmpty(topic))
    {
        Console.Error.WriteLine("No topic provided. Exiting.");
        return 1;
    }
}

Console.WriteLine();
Console.ForegroundColor = ConsoleColor.Yellow;
Console.WriteLine($"Researching: {topic}");
Console.WriteLine("This may take a minute while the agent searches and reads sources...");
Console.ResetColor();
Console.WriteLine();

// --- Run the agent ---
using var cts = new CancellationTokenSource(TimeSpan.FromMinutes(3));

var session = await agent.CreateSessionAsync(cancellationToken: cts.Token);
var response = await agent.RunAsync(
    $"Please research the following topic and provide a comprehensive summary: {topic}",
    session,
    cancellationToken: cts.Token);

// --- Display results ---
Console.ForegroundColor = ConsoleColor.Green;
Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("  Research Summary");
Console.WriteLine("═══════════════════════════════════════════");
Console.ResetColor();
Console.WriteLine();
Console.WriteLine(response.Text);
Console.WriteLine();

if (response.Usage is { } usage)
{
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"[Tokens — Input: {usage.InputTokenCount}, Output: {usage.OutputTokenCount}, Total: {usage.TotalTokenCount}]");
    Console.ResetColor();
}

return 0;

